class Solution:
    def minimizeSet(self, divisor1, divisor2, uniqueCnt1, uniqueCnt2):
        m = 0
        only_d1 = only_d2 = neither = 0
        target = uniqueCnt1 + uniqueCnt2
        while True:
            m += 1
            d1 = (m % divisor1 == 0)
            d2 = (m % divisor2 == 0)
            if d1 and d2:
                pass
            elif d1:
                only_d1 += 1
            elif d2:
                only_d2 += 1
            else:
                neither += 1
            if (only_d2 + neither >= uniqueCnt1 and
                    only_d1 + neither >= uniqueCnt2 and
                    only_d1 + only_d2 + neither >= target):
                return m

