var minimizeSet = function(divisor1, divisor2, uniqueCnt1, uniqueCnt2) {
    function gcd(a, b) { while (b) { const t = a % b; a = b; b = t; } return a; }
    const g = gcd(divisor1, divisor2);
    const lcm = (divisor1 / g) * divisor2;
    function feasible(m) {
        const d1 = Math.floor(m / divisor1);
        const d2 = Math.floor(m / divisor2);
        const dl = Math.floor(m / lcm);
        const onlyD1 = d1 - dl;
        const onlyD2 = d2 - dl;
        const neither = m - d1 - d2 + dl;
        return onlyD2 + neither >= uniqueCnt1 &&
               onlyD1 + neither >= uniqueCnt2 &&
               onlyD1 + onlyD2 + neither >= uniqueCnt1 + uniqueCnt2;
    }
    let lo = 1, hi = Math.max(2, uniqueCnt1 + uniqueCnt2);
    while (!feasible(hi)) hi *= 2;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (feasible(mid)) hi = mid; else lo = mid + 1;
    }
    return lo;
};
